-- Enrichment batch: Similarweb, SimplePractice, SimplyBook.me, SingleStore, Sisense, Sketch, Skillshare, Sling
-- Publishes 8 bulk-imported tool(s) with full editorial content.

-- ── Similarweb ──────────────────────────────────────────────
UPDATE tools SET
  short_description = $q$Digital intelligence platform estimating website and app traffic, researching keywords, and benchmarking competitors and markets.$q$,
  pricing_model = $q$Freemium$q$,
  starting_price = $q$From approximately $125-$199/month (billed annually); higher tiers and Enterprise are sales-quoted$q$,
  founded_year = 2007,
  company_size = $q$1,000-5,000 employees$q$,
  headquarters = $q$New York, NY, USA / Tel Aviv, Israel$q$,
  languages = ARRAY[$q$English$q$]::text[],
  seo_meta_description = $q$Similarweb estimates website and app traffic, tracks competitors, and benchmarks markets with keyword research and industry analytics.$q$,
  og_description = $q$Similarweb estimates website and app traffic, tracks competitors, and benchmarks markets with keyword research and industry analytics.$q$,
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6ec8c9fb-dc39-4341-8a0f-b8c3e18a508d';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = '6ec8c9fb-dc39-4341-8a0f-b8c3e18a508d' AND logo IS NULL AND website IS NOT NULL;









