INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Clinical documentation templates$q$, $q$Customizable progress notes and treatment plan templates built for behavioral health and wellness fields.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$AI Note Taker (add-on)$q$, $q$An optional add-on that drafts session documentation from audio to speed up note writing.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Group practice management$q$, $q$Team scheduling, permissions, and billing oversight for practices with multiple clinicians.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Analytics dashboard$q$, $q$Reporting on appointments, billing, and practice performance on higher-tier plans.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Mobile apps$q$, $q$iOS and Android apps for clinicians and clients to manage scheduling, messaging, and telehealth on the go.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Combines scheduling, billing, notes, and telehealth in one system instead of several separate tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Documentation templates are tailored to behavioral health and wellness professions$q$, 1);
