INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Client portal and mobile apps make booking and communication easier for clients$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Guided onboarding makes setup manageable for clinicians new to practice management software$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$No permanent free plan, and pricing increases as clinicians add clinicians, AI notes, or e-prescribing$q$, 0);
