INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$What is SimplePractice used for?$q$, $q$SimplePractice is practice management and EHR software for therapists, counselors, dietitians, and other health and wellness professionals, covering scheduling, billing, documentation, and telehealth.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Does SimplePractice offer a free trial?$q$, $q$Yes, SimplePractice offers a free trial period so practices can test scheduling, billing, and documentation features before subscribing to a paid plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$How much does SimplePractice cost?$q$, $q$Plans are billed monthly per clinician, starting around $49/month for the Starter plan, with Essential and Plus tiers priced higher for additional features.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Is SimplePractice only for therapists?$q$, $q$No, while therapists and counselors are a large part of its user base, SimplePractice is also used by dietitians, speech-language pathologists, occupational and physical therapists, and other wellness practitioners.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Does SimplePractice support telehealth?$q$, $q$Yes, SimplePractice includes built-in HIPAA-compliant video sessions so clinicians can hold remote appointments without a separate video platform.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Solo therapy private practice$q$, $q$A single therapist manages scheduling, insurance billing, and session notes without hiring separate administrative staff.$q$, $q$Solo psychotherapists and counselors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Group behavioral health practice$q$, $q$A multi-clinician practice coordinates shared scheduling, team permissions, and centralized billing across providers.$q$, $q$Group practice owners and office managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Remote and hybrid client care$q$, $q$A provider offers both in-person and telehealth appointments through one integrated scheduling and video system.$q$, $q$Clinicians offering telehealth services$q$, 2);
