INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Essential$q$, $q$$79/month per clinician$q$, $q$monthly$q$, $q$["Everything in Starter","Appointment reminders","Client messaging","Calendar sync","Custom treatment plans","Analytics dashboard"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Plus$q$, $q$$99/month per clinician$q$, $q$monthly$q$, $q$["Everything in Essential","Client announcements","Group telehealth","Premium phone support","Team member management"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$SimplePractice is a cloud-based electronic health record (EHR) and practice management platform built for health and wellness professionals who run their own caseload. Founded in 2012 and headquartered in Santa Monica, California, the company has grown into one of the most widely used systems for solo clinicians and small group practices in the United States, particularly within behavioral health and outpatient wellness care.$q$, $q$The platform brings together the day-to-day operational pieces of running a practice: appointment scheduling, a client-facing portal, secure messaging, billing and insurance claim submission, telehealth video sessions, and clinical documentation. Rather than stitching together separate tools for calendars, payments, video calls, and notes, practitioners manage all of it from a single HIPAA-compliant system, which reduces the number of logins, subscriptions, and data-entry steps a practice has to juggle every week.$q$, $q$SimplePractice is delivered as a web application with companion mobile apps, so clinicians can review schedules, write notes, or message clients from a desktop or a phone between sessions. It targets independent practitioners and small-to-mid-size group practices rather than large hospital systems, positioning itself as the administrative backbone for a private practice rather than a full hospital-grade EHR built for institutional care settings. That focus shapes nearly every feature decision the company makes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$who-simplepractice-is-for$q$, $q$Who SimplePractice Is For$q$, 2, ARRAY[$q$SimplePractice is built primarily for licensed health and wellness professionals who see clients on an appointment basis: psychotherapists, counselors, psychologists, social workers, marriage and family therapists, speech-language pathologists, occupational and physical therapists, dietitians, and massage or bodywork practitioners. Solo practitioners just starting a private practice, often transitioning from an employed role at a clinic or hospital, are a core audience.$q$, $q$It also serves small and mid-size group practices that need to manage several clinicians under one account, split billing responsibilities, and standardize documentation templates across a team. Practices that rely heavily on U.S. insurance billing benefit from its built-in claim filing and eligibility checking, since that workflow is a central, time-consuming part of running a behavioral health or wellness business day to day.$q$, $q$Clinicians who want a single system instead of juggling separate scheduling apps, a payment processor, a video-call tool, and a paper or generic-document note system are a strong fit, especially those who value a guided setup process over building a highly customized workflow from scratch. It also suits practitioners who want clients to book, pay, and message through one branded, professional-looking portal without any technical setup work.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large hospital systems, multi-specialty medical groups, or enterprise healthcare organizations that need deep interoperability with hospital EHRs, lab systems, or complex care-coordination workflows will likely find SimplePractice too narrowly scoped. It is designed around the outpatient, appointment-based private practice model rather than institutional or hospital-based healthcare delivery.$q$, $q$Practitioners located outside the United States may also find it a poor fit, since billing, insurance claim formats, and compliance features are built around U.S. payers and regulations rather than other countries' healthcare or insurance systems, which can leave international clinicians without the localized billing workflows they actually need day to day.$q$, $q$Practices that need heavy customization, extensive third-party integrations through an open API, or a permanently free tool should look elsewhere: SimplePractice has no lasting free plan beyond the trial, and its total monthly cost rises as clinicians add features like AI notes, e-prescribing, or additional team members on the group practice tiers. Budget-conscious solo practitioners should map out likely add-ons before committing to a plan.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Core functionality includes online scheduling with calendar sync, a client portal for intake paperwork and appointment requests, secure client messaging, and automated appointment reminders that help cut down on missed sessions and last-minute cancellations. Billing tools cover invoicing, credit card payment processing, insurance eligibility checks, and electronic claim submission, which together handle much of the financial side of running a practice.$q$, $q$Clinical documentation is built around customizable note and treatment-plan templates designed for behavioral health and wellness disciplines, along with built-in telehealth video sessions for remote appointments. Higher tiers add group practice management, team member permissions, client announcements, out-of-office scheduling, and an analytics dashboard for tracking practice performance over time.$q$, $q$Add-on capabilities extend the core plans further, including an AI-assisted note-taking tool that drafts documentation from session audio, and electronic prescribing for eligible clinicians. Mobile apps for iOS and Android let clinicians and clients manage scheduling, messaging, and telehealth from a phone, so the day-to-day experience does not depend on being at a desktop computer.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$the-simplepractice-experience$q$, $q$The SimplePractice Experience$q$, 2, ARRAY[$q$New users typically go through a guided setup that walks through calendar configuration, client portal branding, and note templates before the free trial period ends. The interface is organized around a practice-wide calendar and client records, which keeps day-to-day navigation between scheduling, notes, and billing fairly consistent across the product rather than scattered across separate menus.$q$, $q$Clinicians moving from paper records or spreadsheets tend to describe the learning curve as manageable, since most workflows follow the natural order of booking an appointment, holding the session, and documenting it afterward. Group practice owners get added visibility into team scheduling and billing status across clinicians, which helps with oversight and accountability as a practice grows beyond one provider.$q$, $q$Because pricing and available features are tiered, the day-to-day experience can vary: practices on lower tiers may need to work around missing features like custom treatment plans or premium phone support that are reserved for higher plans, so getting the most value out of the platform often means matching the plan to how the practice actually operates and which add-ons are genuinely needed.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
