INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Online booking widget$q$, $q$An embeddable or hosted booking page lets clients view availability and schedule appointments without calling the business.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Client mobile app$q$, $q$A branded client app allows customers to book, reschedule, and receive reminders from their phone.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Custom features marketplace$q$, $q$Optional add-ons such as memberships, packages, gift cards, and point-of-sale can be enabled individually as a business grows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Automated notifications$q$, $q$Email and other automated reminders help reduce missed appointments and keep clients informed of changes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Calendar sync$q$, $q$Two-way sync with Google Calendar, Outlook, and iCal keeps staff schedules consistent across tools.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Online payments$q$, $q$Integrated payment processing lets businesses collect deposits or full payment at the time of booking.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Multi-language and multi-currency support$q$, $q$The booking interface can be configured in numerous languages and currencies for international clients.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Reports and analytics$q$, $q$Built-in reporting gives visibility into bookings, revenue, and staff utilization over time.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Third-party integrations$q$, $q$Connections to platforms like WordPress, Facebook, Instagram, and Zapier extend booking to where clients already are.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Multi-location management$q$, $q$Businesses with several branches or providers can manage schedules across locations from a single account.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Usable free plan that lets very small businesses start booking online without a credit card$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Wide industry applicability, from salons and clinics to tutors and consultants$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Modular add-on marketplace lets businesses pay only for the extra capabilities they need$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Broad language and currency support suits international or multilingual client bases$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Client-facing mobile app and booking pages are generally easy for end customers to use$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Add-on pricing model can make total cost less predictable than a simple flat-rate competitor$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Booking and staff limits on lower tiers can force an upgrade sooner than expected for growing businesses$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Admin interface and feature marketplace have a learning curve compared to more minimalist schedulers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Some advanced integrations and branding options are reserved for higher-priced plans$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Design customization of the booking page is more limited than dedicated website builders$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Does SimplyBook.me have a free plan?$q$, $q$Yes, SimplyBook.me offers a free plan with a limited number of monthly appointments and one custom feature, designed for solo providers just getting started with online booking.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Is a free trial available for paid plans?$q$, $q$New accounts typically start with a trial period of premium features before deciding whether to stay on the free plan or upgrade to a paid tier.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Can I accept payments through SimplyBook.me?$q$, $q$Yes, paid plans support integrated online payment processing so clients can pay deposits or full amounts when booking an appointment.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$What kinds of businesses use SimplyBook.me?$q$, $q$It is used across many appointment-based service industries, including salons and spas, health and wellness practices, tutoring and coaching, and consulting.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Does SimplyBook.me offer a mobile app?$q$, $q$Yes, there are client-facing mobile apps that let customers browse availability and manage their own bookings from a phone.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Solo service provider getting online for the first time$q$, $q$A single hairdresser, therapist, or tutor sets up a free or entry-level plan to replace phone-based scheduling with a self-service booking page.$q$, $q$Independent professionals and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Multi-staff salon or clinic coordination$q$, $q$A salon or clinic with several staff members manages individual calendars, services, and client notifications from one shared dashboard.$q$, $q$Small salons, spas, and healthcare practices$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Adding paid extras to a growing business$q$, $q$A business enables add-ons like memberships, packages, or point-of-sale as it expands beyond basic appointment booking.$q$, $q$Growing service businesses scaling their operations$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Serving an international client base$q$, $q$A business configures multiple languages and currencies on its booking page to serve clients across different countries.$q$, $q$Businesses with international or multilingual customers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, $q$["Up to 50 bookings per month","1 custom feature","Booking widget and client app","Basic email notifications"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Basic$q$, $q$$11.90/month billed annually ($13.90 billed monthly)$q$, $q$Monthly or annual$q$, $q$["Up to 100 bookings per month","3 custom features","Up to 5 staff providers","Core booking website and admin app"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Standard$q$, $q$$24.90/month billed annually ($29.90 billed monthly)$q$, $q$Monthly or annual$q$, $q$["Up to 500 bookings per month","8 custom features","Up to 15 staff providers","Branded client app options"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Premium$q$, $q$$49.90/month billed annually ($59.90 billed monthly)$q$, $q$Monthly or annual$q$, $q$["Up to 2,000 bookings per month","Unlimited custom features","Up to 30 staff providers","Advanced payment and accounting integrations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$SimplyBook.me is an online appointment scheduling platform built for small and mid-sized service businesses that need clients to book and pay for appointments without phone calls or manual calendars. Founded in 2009 and now part of the team.blue group of companies, it has grown into a widely used booking system serving businesses across many countries and industries.$q$, $q$Rather than shipping every feature to every customer, SimplyBook.me is organized around a core booking engine plus an add-on marketplace of optional custom features, such as memberships, gift cards, point-of-sale, and video conferencing, that businesses can switch on as needed. This modular approach keeps the base product simple while letting more advanced businesses tailor the system to their workflow.$q$, $q$The platform is aimed squarely at appointment-based businesses rather than general-purpose project or team scheduling, and it competes with tools like Acuity Scheduling, Setmore, and Calendly for the small-business booking market. Its differentiator is depth of industry-specific configuration combined with an accessible free tier.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$who-simplybook-me-is-for$q$, $q$Who SimplyBook.me Is For$q$, 2, ARRAY[$q$Solo practitioners and small teams in service industries are the core audience: hairdressers, spa and beauty professionals, massage therapists, tutors, consultants, and personal trainers who need a booking page and calendar without building custom software.$q$, $q$Healthcare-adjacent and appointment-heavy small businesses also fit well, since features like HIPAA-oriented options, intake forms, and automated reminders reduce no-shows and administrative overhead for clinics, therapists, and wellness studios.$q$, $q$Multi-location or multi-provider businesses that have outgrown a single shared calendar can use SimplyBook.me's provider and location management, along with paid add-ons, to coordinate several staff members' schedules from one dashboard.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Businesses wanting a single flat monthly price with everything unlocked may find the add-on marketplace model confusing, since many useful capabilities are gated behind per-feature or per-tier limits rather than bundled by default.$q$, $q$Larger enterprises needing deep native CRM, advanced workforce management, or highly bespoke workflows may outgrow the platform's configuration options and need a more specialized or fully custom-built solution instead.$q$, $q$Teams whose primary need is internal team scheduling or meeting coordination, rather than client-facing appointment booking, are usually better served by tools purpose-built for that use case rather than an appointment-booking platform like SimplyBook.me.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, SimplyBook.me provides a customizable booking widget and hosted booking page, a client-facing mobile app, and an admin dashboard for managing appointments, staff, and services from one place.$q$, $q$Automated email and notification reminders help reduce no-shows, while calendar sync with Google, Outlook, and iCal keeps provider schedules aligned across tools businesses already use.$q$, $q$The custom features marketplace extends the base product with add-ons such as online payments, memberships and packages, gift cards, point-of-sale, waitlists, and integrations with platforms like WordPress, Facebook, Instagram, and Zapier, letting each business assemble the functionality it actually needs.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$the-simplybook-me-experience$q$, $q$The SimplyBook.me Experience$q$, 2, ARRAY[$q$New users typically start with a guided setup wizard that configures services, staff, and working hours, and the free plan allows a business to launch a working booking page without entering payment details.$q$, $q$The interface is functional and configuration-dense rather than flashy; users generally report a learning curve when exploring the custom features marketplace, since discovering and enabling the right add-ons for a given workflow takes some initial exploration.$q$, $q$Support is available through a help center, ticketing system, and community documentation, and the client-facing booking pages and mobile apps are generally described as straightforward for end customers, even where the admin side has more depth to learn.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
