INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b41cb4-0b11-4480-ad3f-317c597ce7a4', $q$Hybrid transactional/analytical processing$q$, $q$Row and columnar storage in one engine let the same database handle fast transactions and large analytical scans without separate systems.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b41cb4-0b11-4480-ad3f-317c597ce7a4', $q$Distributed SQL architecture$q$, $q$A shared-nothing, horizontally scalable cluster design distributes data and query execution across nodes for high concurrency and throughput.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b41cb4-0b11-4480-ad3f-317c597ce7a4', $q$Vector search$q$, $q$Native vector data types and similarity search functions can be combined with relational filters in standard SQL for AI-driven applications.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b41cb4-0b11-4480-ad3f-317c597ce7a4', $q$MySQL wire protocol compatibility$q$, $q$Standard SQL and MySQL-compatible connectivity allow existing drivers, ORMs, and BI tools to connect with minimal changes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b41cb4-0b11-4480-ad3f-317c597ce7a4', $q$Built-in data ingestion pipelines$q$, $q$Native pipelines continuously load data from sources such as Kafka, S3, and other cloud storage without separate ETL infrastructure.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b41cb4-0b11-4480-ad3f-317c597ce7a4', $q$Autoscaling compute$q$, $q$Compute resources can scale up or down based on workload demand, helping match spend to actual usage.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b41cb4-0b11-4480-ad3f-317c597ce7a4', $q$Workload management$q$, $q$Resource governance features isolate and prioritize queries so heavy analytical jobs do not starve latency-sensitive transactional workloads.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b41cb4-0b11-4480-ad3f-317c597ce7a4', $q$Point-in-time recovery and backups$q$, $q$Automated backup and recovery capabilities help protect against data loss and support restoring a database to a prior state.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b41cb4-0b11-4480-ad3f-317c597ce7a4', $q$Multi-cloud deployment$q$, $q$Helios runs on major cloud providers, and self-managed deployment options exist for teams that need on-premises or private infrastructure.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b41cb4-0b11-4480-ad3f-317c597ce7a4', $q$Full-text and JSON search$q$, $q$Built-in full-text search and native JSON handling support semi-structured data and text queries alongside relational data.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09b41cb4-0b11-4480-ad3f-317c597ce7a4', $q$Combines transactional and analytical workloads in a single database, reducing the need for separate ETL pipelines$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09b41cb4-0b11-4480-ad3f-317c597ce7a4', $q$MySQL wire protocol and ANSI SQL support ease adoption for teams already familiar with relational databases$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09b41cb4-0b11-4480-ad3f-317c597ce7a4', $q$Native vector search integrated with SQL simplifies building AI and retrieval-augmented generation features$q$, 2);
