INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aec91730-c8dd-4844-8f50-8eb053c6b5c4', $q$Broad Connector Library$q$, $q$Prebuilt connectors to common databases, cloud warehouses, and SaaS applications.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aec91730-c8dd-4844-8f50-8eb053c6b5c4', $q$Role-Based Access Control$q$, $q$Governance settings for controlling who can view, edit, or embed specific dashboards and models.$q$, 6);
