INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aec91730-c8dd-4844-8f50-8eb053c6b5c4', $q$REST APIs$q$, $q$Programmatic access for automating data refreshes, user management, and platform administration.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aec91730-c8dd-4844-8f50-8eb053c6b5c4', $q$Deep data modeling capabilities for blending complex, multi-source data$q$, 0);
