INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$On-Demand Video Classes$q$, $q$Thousands of streaming classes across creative, business, and lifestyle categories, broken into short, focused lessons.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Project-Based Learning$q$, $q$Every class includes a hands-on project so learners apply what they watch instead of just consuming video passively.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Skillshare Originals$q$, $q$Higher-production flagship classes and series taught by well-known practitioners, included with a Premium membership.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Offline Downloads$q$, $q$Members can download classes in the iOS and Android apps to watch without an internet connection.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Community Project Galleries$q$, $q$Learners upload finished class projects for peer feedback, creating a public portfolio of completed work.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$iOS and Android Apps$q$, $q$Native mobile apps mirror the web experience, syncing progress, bookmarks, and downloads across devices.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Teacher Publishing Tools$q$, $q$Instructors get class creation tools, performance analytics, and a referral program for growing their audience.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Curated Collections$q$, $q$Staff-picked class collections and trending lists help members discover new topics across the catalog.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Class Bookmarking and Progress Tracking$q$, $q$Members can save classes to a wishlist and track lesson completion across sessions and devices.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Free Trial Access$q$, $q$New members get a trial period with full access to the paid catalog before any subscription charge applies.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Large, frequently updated catalog spanning creative and business topics$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Short, practical, project-based classes fit into busy schedules$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$One subscription covers unlimited classes instead of paying per course$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Community feedback through project galleries adds accountability$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Mobile apps with offline downloads suit learning on the go$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$No accredited certificates or credentials recognized by employers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Teacher feedback is inconsistent and rarely personalized$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Annual membership can be poor value for someone needing only one topic$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Class quality varies since almost anyone can publish a class$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Limited free tier restricts most content behind a paid membership$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Is Skillshare free?$q$, $q$Skillshare has a free plan that gives access to a limited selection of classes; the majority of the catalog requires a paid Premium membership.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$How much does a Skillshare membership cost?$q$, $q$Premium membership is billed annually at $167.88 per year, equivalent to $13.99 per month; a month-to-month option is also available at a higher effective rate.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Does Skillshare offer a free trial?$q$, $q$Yes, new members typically get a trial period with full access to the paid catalog, with trial length varying between the website and the mobile apps.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Does Skillshare give certificates of completion?$q$, $q$No, Skillshare does not issue accredited certificates or credentials; completing a class and its project is informal and not tied to formal recognition.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Can I watch Skillshare classes offline?$q$, $q$Yes, Premium members can download classes within the iOS and Android apps for offline viewing.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Building a creative side hustle$q$, $q$Learning illustration, design, or photography skills through short project-based classes to start freelancing or selling creative work.$q$, $q$Creative hobbyists and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Upskilling in marketing and business basics$q$, $q$Picking up practical marketing, branding, or productivity skills to apply directly to a small business or side project.$q$, $q$Small-business owners and marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Exploring a potential career change$q$, $q$Sampling classes across UX, video editing, or writing to test interest in a new field before committing to formal training.$q$, $q$Career switchers and students$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Teaching and monetizing expertise$q$, $q$Publishing classes to reach an existing audience or build a new one, earning revenue based on watch time and referrals.$q$, $q$Working professionals and practitioners$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Access to a limited selection of classes","Browse the full class catalog","Join class discussions","No offline downloads"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Premium Annual$q$, $q$$167.88/year$q$, $q$Annual$q$, $q$["Unlimited access to the full class catalog","Offline downloads on iOS and Android","Ad-free viewing","Access to Skillshare Originals"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$Premium Monthly$q$, $q$Approximately $32/month$q$, $q$Monthly$q$, $q$["Unlimited access to the full class catalog","Offline downloads on iOS and Android","Ad-free viewing","Cancel anytime without an annual commitment"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Skillshare is an online learning community founded in 2010 and headquartered in New York City. The platform hosts tens of thousands of short, video-based classes covering creative and business topics such as graphic design, illustration, photography, filmmaking, writing, marketing, and entrepreneurship. Rather than positioning itself as an accredited school, Skillshare frames learning as a hands-on, community-driven practice, pairing each class with a project students complete and share for feedback from peers and the teaching instructor.$q$, $q$Access follows a freemium subscription model. Anyone can browse the catalog and take a limited number of free classes without payment, while a paid annual or monthly membership unlocks the full library, offline downloads, and ad-free viewing. Instructors, often working professionals rather than academics, earn revenue based on watch minutes and referrals, which has attracted a broad and constantly refreshed roster of practical, skills-focused instructors across dozens of subcategories.$q$, $q$Skillshare is available on the web and through iOS and Android apps, letting members switch between desktop planning and mobile, on-the-go viewing. The company positions itself as a complement to formal education and professional certifications rather than a replacement, emphasizing quick, applicable skills over long-form academic rigor. Its community layer, project galleries, and class discussions differentiate it from purely passive video-course marketplaces, giving the platform a more social, workshop-like feel than a typical streaming catalog.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$who-skillshare-is-for$q$, $q$Who Skillshare Is For$q$, 2, ARRAY[$q$Skillshare suits creative hobbyists and side-hustlers who want to pick up a new craft, such as watercolor painting, lettering, or photo editing, without committing to a semester-long course. Its short class format, often 20 to 60 minutes, fits into evenings or weekends, and the project-based structure gives learners a tangible piece of work to show for their time rather than just passive viewing.$q$, $q$Freelancers and small-business owners looking to sharpen adjacent skills, like design, social media marketing, copywriting, or basic bookkeeping, will find a wide breadth of practical, low-stakes classes. Because the catalog spans creative, business, and lifestyle categories, career switchers exploring a new field, such as illustration, UX, or video editing, can sample many disciplines under a single subscription before investing in specialized training.$q$, $q$It also works well for people who value community feedback: students who complete class projects can share them for critique in project galleries, which suits learners who want structured accountability rather than a purely solitary self-study path. Teachers building an audience or supplemental income also gravitate to the platform for its low barrier to publishing a class, and international learners benefit from an interface and subtitle support offered in several languages.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Learners seeking recognized certificates, university credit, or credentials that carry weight with employers should look elsewhere; Skillshare classes do not carry accredited certification and completion is informal. Anyone pursuing a rigorous, sequenced technical curriculum, such as a full computer-science degree, an accounting qualification, or a regulated professional license, will find the catalog too shallow and unstructured for that purpose.$q$, $q$People who prefer live instructor interaction, graded assignments, or one-on-one mentorship may find Skillshare's asynchronous, video-only format limiting, since teachers rarely provide personalized feedback beyond occasional project comments. Enterprises needing formal compliance training, detailed reporting, or learning-management-system-compatible content should consider dedicated corporate training vendors instead.$q$, $q$Budget-sensitive learners who only need a single topic covered once may find an annual membership poor value compared to buying one targeted course elsewhere, since Skillshare's pricing assumes ongoing, broad usage across many classes rather than a single purchase. Those without reliable internet for streaming video will also struggle outside of the app's offline download feature, and learners who prefer text-based tutorials or long-form written documentation over video will not find that format well represented on the platform.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The core of Skillshare is its on-demand video class library, organized into categories like design, illustration, photography, film and video, business, and writing, with most classes broken into short lessons. Every class pairs its lessons with a class project, which learners complete and upload for peer review, reinforcing the platform's practice-first philosophy over passive consumption.$q$, $q$Skillshare Originals are higher-production, in-depth classes and series taught by well-known practitioners, positioned as premium content within the membership. The mobile apps for iOS and Android support offline downloads for viewing without an internet connection, along with saving classes and tracking progress across devices, syncing with the web experience.$q$, $q$Community features include project galleries, class discussions, and the ability to follow favorite teachers for updates on new releases. Teachers get access to publishing tools, class analytics, and a referral program, while learners can bookmark classes, build wishlists, and browse curated collections and staff picks to help navigate the large and growing catalog. The interface and much of the class captioning are also localized into several languages beyond English.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', $q$the-skillshare-experience$q$, $q$The Skillshare Experience$q$, 2, ARRAY[$q$New visitors land on a browsing-first homepage organized by curated collections, trending classes, and personalized recommendations based on prior activity. Signing up is fast, typically requiring only an email or social login, and a free trial period gives new members unrestricted access to the paid catalog before any annual charge applies.$q$, $q$Once inside, the interface favors visual browsing over search-driven discovery, with thumbnail-heavy class cards, instructor bios, and student project galleries front and center on class pages. Playback includes adjustable speed and class-level bookmarking, while the class project workflow nudges learners to upload their own work before moving to the next class.$q$, $q$Cancellation is self-service through account settings, and membership can typically be paused or ended without contacting support, which keeps the experience low-friction for casual, exploratory learners. Overall, Skillshare feels less like a traditional course platform and more like a subscription video library layered with light social and portfolio-building mechanics, rewarding learners who show up regularly and finish projects rather than those looking for a single, one-off tutorial.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f40d2d28-fdc6-4f97-93db-e7e3e49b3d87', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
